### 任务 4: 添加 API 性能和负载测试 🚀 **P1 - 重要**

**问题描述**: 缺少 API 性能基准测试

**解决方案**:

**文件**: `tests/performance/api-load.test.ts`

```typescript
import { describe, it, expect, beforeAll, afterAll } from '@jest/globals'
import { FastifyInstance } from 'fastify'
import { buildServer } from '../../src/dashboard/server'

describe('API Load Tests', () => {
  let app: FastifyInstance

  beforeAll(async () => {
    app = await buildServer()
    await app.listen({ port: 0 })
  })

  afterAll(async () => {
    await app.close()
  })

  it('handles 1000 concurrent requests', async () => {
    const address = app.server.address() as any
    const baseUrl = `http://localhost:${address.port}`

    // 发送 1000 个并发请求
    const requests = Array.from({ length: 1000 }, () =>
      fetch(`${baseUrl}/api/system/health`)
    )

    const startTime = Date.now()
    const responses = await Promise.all(requests)
    const duration = Date.now() - startTime

    expect(responses).toHaveLength(1000)
    expect(responses.every(r => r.ok)).toBe(true)
    expect(duration).toBeLessThan(5000) // 5秒内完成

    // 计算 P99 延迟
    const p99Index = Math.floor(1000 * 0.99)
    expect(duration / 1000).toBeLessThan(100) // P99 < 100ms
  })

  it('maintains response time under load', async () => {
    const address = app.server.address() as any
    const baseUrl = `http://localhost:${address.port}`

    const durations: number[] = []

    // 发送 100 个请求，记录每个响应时间
    for (let i = 0; i < 100; i++) {
      const start = Date.now()
      await fetch(`${baseUrl}/api/iterations?page=1&limit=20`)
      durations.push(Date.now() - start)
    }

    // 计算统计数据
    const avg = durations.reduce((a, b) => a + b, 0) / durations.length
    const max = Math.max(...durations)
    const min = Math.min(...durations)
    const p95 = durations.sort((a, b) => a - b)[94]

    expect(avg).toBeLessThan(50) // 平均 < 50ms
    expect(p95).toBeLessThan(100) // P95 < 100ms
    expect(max).toBeLessThan(200) // 最大 < 200ms

    console.log(`API Response Times: avg=${avg}ms, min=${min}ms, max=${max}ms, p95=${p95}ms`)
  })
})
```

**预期成果**:
- ✅ API 并发处理能力验证
- ✅ P99 响应时间 < 100ms
- ✅ 性能基准建立

**时间**: 1 天

