  beforeEach(() => {
    agent = new ProductManagerAgent()
    agent.setPermissionMode('bypassPermissions')
    agent.setHistoryFile('/tmp/test-product-manager.json')
  })

  it('analyzes project structure', async () => {
    vi.spyOn(fs, 'readdirSync').mockReturnValue(['src', 'tests', 'package.json'])
