**文件**: `dashboard/src/api/websocket.ts`

```typescript
import { ref, reactive } from 'vue';

type EventHandler = (data: any) => void;

export class WebSocketClient {
  private ws: WebSocket | null = null;
  private url: string;
  private reconnectTimer: any = null;
  private heartbeatTimer: any = null;
  private messageQueue: any[] = [];
  private handlers = reactive<Record<string, Set<EventHandler>>>({});

  public status = ref<'connecting' | 'connected' | 'disconnected'>('disconnected');
  public reconnectAttempts = ref(0);
  public readonly maxReconnectAttempts = 5;

  constructor(url: string) {
    this.url = url;
  }

  connect() {
    if (this.ws?.readyState === WebSocket.OPEN) return;

    this.status.value = 'connecting';
    this.ws = new WebSocket(this.url);

    this.ws.onopen = () => {
      this.status.value = 'connected';
      this.reconnectAttempts.value = 0;
      this.startHeartbeat();
      this.flushMessageQueue();
    };

    this.ws.onclose = () => {
      this.status.value = 'disconnected';
      this.stopHeartbeat();
      this.scheduleReconnect();
    };

    this.ws.onerror = (error) => {
      console.error('WebSocket error:', error);
    };

    this.ws.onmessage = (event) => {
      try {
        const { type, data } = JSON.parse(event.data);
        this.handlers[type]?.forEach(handler => handler(data));
      } catch (error) {
        console.error('Failed to parse message:', error);
      }
    };
  }

  disconnect() {
    this.stopHeartbeat();
    clearTimeout(this.reconnectTimer);
    this.ws?.close();
    this.ws = null;
  }

  send(type: string, data: any) {
    const message = JSON.stringify({ type, data });

    if (this.ws?.readyState === WebSocket.OPEN) {
      this.ws.send(message);
    } else {
      this.messageQueue.push({ type, data });
    }
  }

  on(event: string, handler: EventHandler) {
    if (!this.handlers[event]) {
      this.handlers[event] = new Set();
    }
    this.handlers[event].add(handler);
  }

  off(event: string, handler: EventHandler) {
    this.handlers[event]?.delete(handler);
  }

  private startHeartbeat() {
    this.heartbeatTimer = setInterval(() => {
      this.send('ping', { timestamp: Date.now() });
    }, 30000);
  }

  private stopHeartbeat() {
    clearInterval(this.heartbeatTimer);
  }

  private scheduleReconnect() {
    if (this.reconnectAttempts.value >= this.maxReconnectAttempts) {
      console.error('Max reconnect attempts reached');
      return;
    }

    const delay = Math.min(1000 * Math.pow(2, this.reconnectAttempts.value), 30000);
    this.reconnectAttempts.value++;

    this.reconnectTimer = setTimeout(() => {
      this.connect();
    }, delay);
  }

  private flushMessageQueue() {
    while (this.messageQueue.length > 0) {
      const message = this.messageQueue.shift();
      this.send(message.type, message.data);
    }
  }
}

// 创建单例
export const wsClient = new WebSocketClient('ws://localhost:3000/ws');
```

