import { ref, onMounted, onUnmounted } from 'vue';
import { useIterationStore } from '../stores/iteration';
import { useAgentStore } from '../stores/agent';
import { useSystemStore } from '../stores/system';
import { wsClient } from '../api/websocket';
import MetricCard from '../components/MetricCard.vue';
import CurrentIterationPanel from '../components/CurrentIterationPanel.vue';
import AgentGrid from '../components/AgentGrid.vue';
import ResourceChart from '../components/charts/ResourceChart.vue';

const iterationStore = useIterationStore();
const agentStore = useAgentStore();
const systemStore = useSystemStore();

const loading = ref(true);
const metrics = ref([]);
const currentIteration = ref(null);
const agents = ref([]);
const resourceData = ref({ cpu: [], memory: [] });

onMounted(async () => {
  // 连接 WebSocket
  wsClient.connect();

  // 订阅事件
  wsClient.on('iteration:updated', handleIterationUpdate);
  wsClient.on('agent:updated', handleAgentUpdate);
  wsClient.on('system:metrics', handleMetricsUpdate);

  // 加载初始数据
  await loadInitialData();
});

onUnmounted(() => {
  wsClient.disconnect();
});

async function loadInitialData() {
  try {
    const [systemMetrics, currentIter] = await Promise.all([
      systemStore.fetchMetrics(),
      iterationStore.fetchCurrent()
    ]);

    metrics.value = [
      { title: '总迭代次数', value: systemMetrics.totalIterations, trend: '+12%', icon: 'DataAnalysis' },
      { title: '平均耗时', value: `${systemMetrics.avgDuration}s`, trend: '-5%', icon: 'Timer' },
      { title: '运行中 Agent', value: systemMetrics.activeAgents, trend: '+3', icon: 'User' },
      { title: '成功率', value: `${systemMetrics.successRate}%`, trend: '+2%', icon: 'SuccessFilled' }
    ];

    currentIteration.value = currentIter;
    agents.value = await agentStore.fetchAll();
    loading.value = false;
  } catch (error) {
    console.error('Failed to load initial data:', error);
  }
}

function handleIterationUpdate(data: any) {
  currentIteration.value = data;
}

function handleAgentUpdate(data: any) {
  const index = agents.value.findIndex(a => a.id === data.id);
  if (index !== -1) {
    agents.value[index] = data;
  }
}

function handleMetricsUpdate(data: any) {
  resourceData.value = data;
}

async function handleStart() {
  await iterationStore.start();
}

async function handleStop() {
  await iterationStore.stop();
}
</script>
```

