**文件 1: dashboard/src/stores/iteration.ts**

```typescript
import { defineStore } from 'pinia';
import { ref } from 'vue';
import axios from 'axios';

export const useIterationStore = defineStore('iteration', () => {
  const current = ref(null);
  const list = ref([]);
  const loading = ref(false);

  async function fetchCurrent() {
    loading.value = true;
    try {
      const response = await axios.get('/api/iterations/current');
      current.value = response.data;
      return response.data;
    } finally {
      loading.value = false;
    }
  }

  async function fetchList(params?: any) {
    loading.value = true;
    try {
      const response = await axios.get('/api/iterations', { params });
      list.value = response.data.items;
      return response.data;
    } finally {
      loading.value = false;
    }
  }

  async function start() {
    const response = await axios.post('/api/iterations/start');
    current.value = response.data;
    return response.data;
  }

  async function stop() {
    await axios.post('/api/iterations/stop');
    current.value = null;
  }

  return {
    current,
    list,
    loading,
    fetchCurrent,
    fetchList,
    start,
    stop
  };
});
```

