#### 任务 4.1: 实现性能监控 (3 小时)

**文件**: `src/dashboard/services/performance.service.ts`

```typescript
import pino from 'pino';

const logger = pino({
  level: 'info',
  transport: {
    target: 'pino-pretty',
    options: { colorize: true }
  }
});

export class PerformanceMonitor {
  private metrics = {
    apiCalls: new Map<string, number[]>(),
    dbQueries: new Map<string, number[]>(),
    wsMessages: 0
  };

  recordApiCall(endpoint: string, duration: number) {
    if (!this.metrics.apiCalls.has(endpoint)) {
      this.metrics.apiCalls.set(endpoint, []);
    }
    this.metrics.apiCalls.get(endpoint)!.push(duration);

    // 警告慢请求
    if (duration > 1000) {
      logger.warn({ endpoint, duration }, 'Slow API call');
    }
  }

  recordDbQuery(query: string, duration: number) {
    if (!this.metrics.dbQueries.has(query)) {
      this.metrics.dbQueries.set(query, []);
    }
    this.metrics.dbQueries.get(query)!.push(duration);
  }

  recordWsMessage() {
    this.metrics.wsMessages++;
  }

  getReport() {
    const report: any = {};

    // 计算平均 API 响应时间
    for (const [endpoint, durations] of this.metrics.apiCalls) {
      const avg = durations.reduce((a, b) => a + b, 0) / durations.length;
      const p99 = durations.sort((a, b) => a - b)[Math.floor(durations.length * 0.99)];
      report[endpoint] = { avg, p99, count: durations.length };
    }

    return report;
  }
}

export const perfMonitor = new PerformanceMonitor();
```

